import { v } from "convex/values";
import { httpAction, internalQuery, internalMutation } from "./_generated/server";
import { internal } from "./_generated/api";

// Unipile webhook receiver — handles new emails, tracking, account status
export const unipileWebhook = httpAction(async (ctx, request) => {
  // Verify Unipile-Auth shared secret
  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  const authHeader = request.headers.get("Unipile-Auth");

  if (secret && authHeader !== secret) {
    console.error("Webhook auth failed: invalid Unipile-Auth header");
    return new Response("Unauthorized", { status: 401 });
  }

  try {
    const payload = await request.json();
    const eventType = payload.event || payload.type;

    switch (eventType) {
      case "new_email":
      case "mail.received":
        await handleNewEmail(ctx, payload);
        break;

      case "email_tracking":
      case "mail.tracking":
        // Log open/click events — useful for analytics
        console.log("Email tracking event:", JSON.stringify(payload));
        break;

      case "account.status":
      case "account_status":
        await handleAccountStatus(ctx, payload);
        break;

      default:
        console.log("Unknown webhook event:", eventType, JSON.stringify(payload));
    }

    return new Response("OK", { status: 200 });
  } catch (error: any) {
    console.error("Webhook processing error:", error);
    return new Response("Internal error", { status: 500 });
  }
});

async function handleNewEmail(ctx: any, payload: any) {
  const email = payload.data || payload;
  const providerId = email.provider_id
    ? JSON.stringify(email.provider_id)
    : "";
  const accountId = email.account_id || "";
  const from = email.from?.identifier || email.from_email || "";
  const threadId = email.thread_id || "";

  // Find the Unipile account to get the userId
  const account = accountId
    ? await ctx.runQuery(internal.webhook.findAccountByUnipileId, {
        unipileAccountId: accountId,
      })
    : null;

  if (!account) {
    console.log("No matching Unipile account for:", accountId);
    return;
  }

  // Check if this email is on a thread with an active enrollment
  if (threadId || providerId) {
    await ctx.runMutation(internal.webhook.processReply, {
      userId: account.userId,
      fromEmail: from,
      threadId,
      providerId,
      messageId: email.id || "",
      subject: email.subject || "",
      snippet: email.body_plain?.substring(0, 200) || "",
    });
  }
}

async function handleAccountStatus(ctx: any, payload: any) {
  const data = payload.data || payload;
  const accountId = data.account_id || "";
  const status = data.status || "";

  if (status === "disconnected" || status === "error") {
    const account = await ctx.runQuery(
      internal.webhook.findAccountByUnipileId,
      { unipileAccountId: accountId }
    );

    if (account) {
      await ctx.runMutation(internal.webhook.markMailboxAuthExpired, {
        userId: account.userId,
        unipileAccountId: accountId,
      });
    }
  }
}

// Unipile account callback — called when user completes hosted auth
export const unipileAccountCallback = httpAction(async (ctx, request) => {
  try {
    const payload = await request.json();
    const accountId = payload.account_id || "";
    const userId = payload.name || ""; // We pass nurge_user_id as 'name'
    const email = payload.identifier || "";

    if (!accountId || !userId) {
      return new Response("Missing account_id or name", { status: 400 });
    }

    await ctx.runMutation(internal.webhook.registerUnipileAccount, {
      userId,
      unipileAccountId: accountId,
      provider: "GOOGLE", // TODO: detect from payload
      email,
    });

    return new Response("OK", { status: 200 });
  } catch (error: any) {
    console.error("Account callback error:", error);
    return new Response("Internal error", { status: 500 });
  }
});

// --- Internal functions used by webhook handlers ---

export const findAccountByUnipileId = internalQuery({
  args: { unipileAccountId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("unipileAccounts")
      .withIndex("by_unipile_id", (q) =>
        q.eq("unipileAccountId", args.unipileAccountId)
      )
      .first();
  },
});

export const processReply = internalMutation({
  args: {
    userId: v.string(),
    fromEmail: v.string(),
    threadId: v.string(),
    providerId: v.string(),
    messageId: v.string(),
    subject: v.optional(v.string()),
    snippet: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    // Find active enrollments for this contact
    const enrollments = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_contact", (q) =>
        q.eq("userId", args.userId).eq("contactEmail", args.fromEmail)
      )
      .collect();

    const activeEnrollments = enrollments.filter(
      (e) => e.status === "active" || e.status === "paused"
    );

    if (activeEnrollments.length === 0) return;

    // Get sync version
    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Stop ALL active enrollments for this contact
    for (const enrollment of activeEnrollments) {
      await ctx.db.patch(enrollment._id, {
        status: "stopped",
        statusReason: "reply received",
        replyState: "needs_classification",
        lastReplyAt: new Date().toISOString(),
        nextDueAt: "",
        syncVersion: version,
      });

      // Cancel all pending tasks
      const tasks = await ctx.db
        .query("followUpTasks")
        .withIndex("by_enrollment", (q) =>
          q.eq("enrollmentId", enrollment.externalId)
        )
        .collect();

      for (const task of tasks) {
        if (task.status === "open") {
          await ctx.db.patch(task._id, {
            status: "canceled",
            sendStatus: "canceled",
            canceledReason: "reply received",
            syncVersion: version,
          });
        }
      }

      // Cancel pending drafts
      const drafts = await ctx.db
        .query("sequenceDrafts")
        .withIndex("by_enrollment", (q) =>
          q.eq("enrollmentId", enrollment.externalId)
        )
        .collect();

      for (const draft of drafts) {
        if (draft.status === "pending") {
          await ctx.db.patch(draft._id, {
            status: "canceled",
            syncVersion: version,
          });
        }
      }

      // Record reply event
      const replyId = `re-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      await ctx.db.insert("replyEvents", {
        externalId: replyId,
        enrollmentId: enrollment.externalId,
        mailboxId: enrollment.mailboxId,
        threadId: args.threadId,
        messageId: args.messageId,
        contactEmail: args.fromEmail,
        classification: "needs_classification",
        subject: args.subject,
        snippet: args.snippet,
        occurredAt: new Date().toISOString(),
        syncVersion: version,
        userId: args.userId,
      });

      version++;
    }

    // Update sync state
    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }
  },
});

export const markMailboxAuthExpired = internalMutation({
  args: { userId: v.string(), unipileAccountId: v.string() },
  handler: async (ctx, args) => {
    // Find mailbox by Unipile account
    const account = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_unipile_id", (q) =>
        q.eq("unipileAccountId", args.unipileAccountId)
      )
      .first();

    if (account) {
      await ctx.db.patch(account._id, { status: "auth_expired" });
    }

    // Find mailboxes associated with this account and mark them
    const mailboxes = await ctx.db
      .query("mailboxes")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .collect();

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    for (const mailbox of mailboxes) {
      if (mailbox.status === "active") {
        await ctx.db.patch(mailbox._id, {
          status: "auth_expired",
          syncVersion: version,
        });
        version++;
      }
    }

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }
  },
});

export const registerUnipileAccount = internalMutation({
  args: {
    userId: v.string(),
    unipileAccountId: v.string(),
    provider: v.string(),
    email: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    // Check if already exists
    const existing = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_unipile_id", (q) =>
        q.eq("unipileAccountId", args.unipileAccountId)
      )
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        status: "connected",
        email: args.email,
      });
      return;
    }

    await ctx.db.insert("unipileAccounts", {
      userId: args.userId,
      provider: args.provider,
      unipileAccountId: args.unipileAccountId,
      email: args.email,
      status: "connected",
      connectedAt: new Date().toISOString(),
    });
  },
});

