  1→import { v } from "convex/values";
  2→import { httpAction, internalQuery, internalMutation } from "./_generated/server";
  3→import { internal } from "./_generated/api";
  4→import { callUnipileSend } from "./send";
  5→import {
  6→  isSuppressed,
  7→  countSendsForDay,
  8→  todayInTimezone,
  9→  withinSendWindow,
 10→} from "./helpers";
 11→
 12→// POST /api/send-email — single endpoint for all CLI-initiated sends
 13→//
 14→// Sync sends (sync: true): calls Unipile immediately, returns result.
 15→// Async sends (sync: false): creates task with pending status, cron picks it up.
 16→// Sequence sends: creates enrollment + future follow-up tasks + drafts.
 17→export const sendEmail = httpAction(async (ctx, request) => {
 18→  try {
 19→    const payload = await request.json();
 20→
 21→    // --- Auth ---
 22→    const authHeader = request.headers.get("Authorization");
 23→    if (!authHeader || !authHeader.startsWith("Bearer ")) {
 24→      return jsonResponse({ ok: false, error: "Missing auth token" }, 401);
 25→    }
 26→    const token = authHeader.slice(7);
 27→
 28→    const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 29→    if (!user) {
 30→      return jsonResponse({ ok: false, error: "Invalid auth token" }, 401);
 31→    }
 32→    const userId = user._id;
 33→
 34→    // --- Validate required fields ---
 35→    const { to, subject, body, sendType, sync, taskId, sequence } = payload;
 36→
 37→    // If taskId is provided, we're sending an existing task
 38→    if (taskId) {
 39→      return await handleExistingTask(ctx, userId, taskId, payload);
 40→    }
 41→
 42→    if (!to || !subject || !body) {
 43→      return jsonResponse({ ok: false, error: "to, subject, and body are required" }, 400);
 44→    }
 45→
 46→    // --- Look up Unipile account ---
 47→    const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 48→      userId,
 49→      provider: "GOOGLE",
 50→    });
 51→    if (!unipileAccount) {
 52→      return jsonResponse({ ok: false, error: "No connected email account. Run: nurge connect gmail" }, 400);
 53→    }
 54→    if (unipileAccount.status === "auth_expired") {
 55→      return jsonResponse({ ok: false, error: "Email account auth expired. Re-authenticate via nurge connect gmail" }, 400);
 56→    }
 57→
 58→    // --- Resolve mailbox ---
 59→    const mailboxId = sequence?.mailboxId || null;
 60→    const mailbox = mailboxId
 61→      ? await ctx.runQuery(internal.sendApi.findMailboxById, { externalId: mailboxId })
 62→      : await ctx.runQuery(internal.sendApi.findActiveMailbox, { userId });
 63→
 64→    if (!mailbox) {
 65→      return jsonResponse({ ok: false, error: "No active mailbox found" }, 400);
 66→    }
 67→    if (mailbox.status === "auth_expired") {
 68→      return jsonResponse({ ok: false, error: "Mailbox auth expired. Re-authenticate via nurge connect gmail" }, 400);
 69→    }
 70→
 71→    // --- Suppression check ---
 72→    const suppression = await ctx.runQuery(internal.sendApi.checkSuppression, { userId, email: to });
 73→    if (suppression.suppressed) {
 74→      return jsonResponse({ ok: false, error: `Contact suppressed: ${suppression.reason}` }, 400);
 75→    }
 76→
 77→    // --- Send window + daily cap ---
 78→    const effectiveSendType = sendType || "first_touch";
 79→    if (!withinSendWindow(mailbox.sendWindowStartHour, mailbox.sendWindowEndHour, mailbox.sendWindowTimezone)) {
 80→      if (sync) {
 81→        return jsonResponse({ ok: false, error: "Outside send window" }, 400);
 82→      }
 83→      // Async: task will be picked up when window opens
 84→    }
 85→
 86→    const today = todayInTimezone(mailbox.sendWindowTimezone);
 87→    const sendCount = await ctx.runQuery(internal.sendApi.countSends, {
 88→      mailboxId: mailbox.externalId,
 89→      sendType: effectiveSendType,
 90→      day: today,
 91→    });
 92→    const capMap: Record<string, number> = {
 93→      first_touch: mailbox.firstTouchDailyCap,
 94→      follow_up: mailbox.followUpDailyCap,
 95→      reply: mailbox.replyDailyCap,
 96→    };
 97→    const cap = capMap[effectiveSendType] || 0;
 98→    if (cap > 0 && sendCount >= cap) {
 99→      if (sync) {
100→        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
101→      }
102→    }
103→
104→    // --- Generate IDs ---
105→    const now = new Date().toISOString();
106→    const taskExternalId = `task-${Date.now()}-${randomSuffix()}`;
107→    const enrollmentExternalId = sequence ? `enr-${Date.now()}-${randomSuffix()}` : "";
108→
109→    // --- Create enrollment + future tasks if sequence ---
110→    if (sequence) {
111→      // Check for existing active enrollment
112→      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
113→        userId,
114→        mailboxId: mailbox.externalId,
115→        contactEmail: to,
116→      });
117→      if (existingEnrollment) {
118→        return jsonResponse({
119→          ok: false,
120→          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
121→        }, 400);
122→      }
123→
124→      await ctx.runMutation(internal.sendApi.createSendEnrollment, {
125→        userId,
126→        enrollment: {
127→          externalId: enrollmentExternalId,
128→          sequenceName: sequence.sequenceName,
129→          campaignName: sequence.campaignName || "",
130→          mailboxId: mailbox.externalId,
131→          contactEmail: to,
132→          contactName: sequence.contactName || "",
133→          subject,
134→          currentStep: 1,
135→          totalSteps: 1 + (sequence.steps?.length || 0),
136→          initialBody: body,
137→          unipileAccountId: unipileAccount.unipileAccountId,
138→        },
139→        firstTask: {
140→          externalId: taskExternalId,
141→          stepNumber: 1,
142→          stepName: "first_touch",
143→          sendType: "first_touch",
144→          dueAt: now,
145→          subject,
146→          body,
147→          contactEmail: to,
148→          mailboxId: mailbox.externalId,
149→        },
150→        futureSteps: (sequence.steps || []).map((step: any, i: number) => {
151→          const stepTaskId = `task-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
152→          const draftId = `draft-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
153→          const dueDate = new Date(Date.now() + (step.delayDays || 3) * 86400000).toISOString();
154→          return {
155→            task: {
156→              externalId: stepTaskId,
157→              stepNumber: step.stepNumber || i + 2,
158→              stepName: step.stepName || `follow_up_${i + 1}`,
159→              sendType: step.sendType || "follow_up",
160→              dueAt: dueDate,
161→              subject: step.subject || subject,
162→              body: step.body || "",
163→              contactEmail: to,
164→              mailboxId: mailbox.externalId,
165→            },
166→            draft: {
167→              externalId: draftId,
168→              taskId: stepTaskId,
169→              stepNumber: step.stepNumber || i + 2,
170→              subject: step.subject || subject,
171→              body: step.body || "",
172→              channel: "email",
173→            },
174→          };
175→        }),
176→      });
177→    } else {
178→      // One-off send: create standalone task
179→      await ctx.runMutation(internal.sendApi.createStandaloneTask, {
180→        userId,
181→        task: {
182→          externalId: taskExternalId,
183→          enrollmentId: "",
184→          mailboxId: mailbox.externalId,
185→          contactEmail: to,
186→          subject,
187→          body,
188→          stepNumber: 1,
189→          sendType: effectiveSendType,
190→          dueAt: now,
191→        },
192→      });
193→    }
194→
195→    // --- Sync: send now ---
196→    if (sync) {
197→      const sendResult = await callUnipileSend({
198→        accountId: unipileAccount.unipileAccountId,
199→        to,
200→        subject,
201→        body,
202→      });
203→
204→      if (!sendResult.ok) {
205→        await ctx.runMutation(internal.sendApi.markTaskFailed, {
206→          userId,
207→          taskId: taskExternalId,
208→          error: sendResult.error,
209→          authError: sendResult.authError,
210→          mailboxId: mailbox.externalId,
211→        });
212→        return jsonResponse({ ok: false, error: sendResult.error }, 502);
213→      }
214→
215→      await ctx.runMutation(internal.sendApi.markTaskSent, {
216→        userId,
217→        taskId: taskExternalId,
218→        enrollmentId: enrollmentExternalId,
219→        mailboxId: mailbox.externalId,
220→        sendType: effectiveSendType,
221→        unipileMessageId: sendResult.messageId,
222→        providerId: sendResult.providerId,
223→      });
224→
225→      return jsonResponse({
226→        ok: true,
227→        messageId: sendResult.messageId,
228→        providerId: sendResult.providerId,
229→        taskId: taskExternalId,
230→        enrollmentId: enrollmentExternalId || undefined,
231→      });
232→    }
233→
234→    // --- Async: return queued ---
235→    return jsonResponse({
236→      ok: true,
237→      queued: true,
238→      taskId: taskExternalId,
239→      enrollmentId: enrollmentExternalId || undefined,
240→    });
241→  } catch (error: any) {
242→    console.error("sendEmail error:", error);
243→    return jsonResponse({ ok: false, error: error.message || "Internal error" }, 500);
244→  }
245→});
246→
247→// Handle sending an existing task (--task-id flow)
248→async function handleExistingTask(ctx: any, userId: string, taskId: string, payload: any) {
249→  const task = await ctx.runQuery(internal.sendApi.findTask, { externalId: taskId });
250→  if (!task) {
251→    return jsonResponse({ ok: false, error: `Task ${taskId} not found` }, 404);
252→  }
253→  if (task.userId !== userId) {
254→    return jsonResponse({ ok: false, error: "Task does not belong to this user" }, 403);
255→  }
256→  if (task.status !== "open") {
257→    return jsonResponse({ ok: false, error: `Task is ${task.status}, not open` }, 400);
258→  }
259→  if (task.sendStatus === "sent") {
260→    return jsonResponse({ ok: false, error: "Task already sent" }, 400);
261→  }
262→
263→  // Resolve Unipile account
264→  const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
265→    userId,
266→    provider: "GOOGLE",
267→  });
268→  if (!unipileAccount) {
269→    return jsonResponse({ ok: false, error: "No connected email account" }, 400);
270→  }
271→
272→  // Use payload overrides or task defaults
273→  const to = payload.to || task.contactEmail;
274→  const subject = payload.subject || task.subject || "";
275→  const body = payload.body || task.body || "";
276→
277→  // Look up draft for latest content
278→  const draft = await ctx.runQuery(internal.sendApi.findDraft, { taskId });
279→  const finalSubject = subject || draft?.subject || "";
280→  const finalBody = body || draft?.body || "";
281→
282→  if (!finalSubject || !finalBody) {
283→    return jsonResponse({ ok: false, error: "No subject or body available for this task" }, 400);
284→  }
285→
286→  // Get enrollment for threading
287→  const enrollment = task.enrollmentId
288→    ? await ctx.runQuery(internal.sendApi.findEnrollment, { externalId: task.enrollmentId })
289→    : null;
290→
291→  const replyTo = enrollment?.unipileThreadProviderId || undefined;
292→
293→  const sendResult = await callUnipileSend({
294→    accountId: unipileAccount.unipileAccountId,
295→    to,
296→    subject: finalSubject,
297→    body: finalBody,
298→    replyTo,
299→  });
300→
301→  if (!sendResult.ok) {
302→    await ctx.runMutation(internal.sendApi.markTaskFailed, {
303→      userId,
304→      taskId,
305→      error: sendResult.error,
306→      authError: sendResult.authError,
307→      mailboxId: task.mailboxId,
308→    });
309→    return jsonResponse({ ok: false, error: sendResult.error }, 502);
310→  }
311→
312→  await ctx.runMutation(internal.sendApi.markTaskSent, {
313→    userId,
314→    taskId,
315→    enrollmentId: task.enrollmentId,
316→    mailboxId: task.mailboxId,
317→    sendType: task.sendType,
318→    unipileMessageId: sendResult.messageId,
319→    providerId: sendResult.providerId,
320→  });
321→
322→  return jsonResponse({
323→    ok: true,
324→    messageId: sendResult.messageId,
325→    providerId: sendResult.providerId,
326→    taskId,
327→    enrollmentId: task.enrollmentId || undefined,
328→  });
329→}
330→
331→function jsonResponse(data: any, status = 200) {
332→  return new Response(JSON.stringify(data), {
333→    status,
334→    headers: { "Content-Type": "application/json" },
335→  });
336→}
